// Get data (Async)
async function getProfil() {
    const db = await fetchDatabase();
    return db.profil || {};
}

async function getUMKM() {
    const db = await fetchDatabase();
    return db.umkm || [];
}

async function getAdmins() {
    const db = await fetchDatabase();
    return db.admins || [];
}

async function getMessages() {
    const db = await fetchDatabase();
    return db.pesan || [];
}

// Save data (used by admin, Async)
async function saveProfil(profilData) {
    const db = await fetchDatabase();
    db.profil = profilData;
    await saveDatabase(db);
}

async function saveUMKM(umkmData) {
    const db = await fetchDatabase();
    db.umkm = umkmData;
    await saveDatabase(db);
}

async function saveAdmins(adminsData) {
    const db = await fetchDatabase();
    db.admins = adminsData;
    await saveDatabase(db);
}

async function saveMessages(messages) {
    const db = await fetchDatabase();
    db.pesan = messages;
    await saveDatabase(db);
}

// Format newline to <br> or <li>
function formatText(text) {
    if (!text) return "";
    return text.replace(/\n/g, '<br>');
}

function formatList(text) {
    if (!text) return "";
    const lines = text.split('\n').filter(line => line.trim() !== '');
    let html = '<ul style="list-style-type: disc; margin-left: 20px; color: var(--text-muted); line-height: 1.8;">';
    lines.forEach(line => {
        html += `<li>${line}</li>`;
    });
    html += '</ul>';
    return html;
}
